函数set search_path to db_mozhengfly;/*通过传入一个字符串和一个自增的ID生成有序的UUID*/DROP FUNCTION IF EXISTS gen_uuid(VARCHAR, INT);CREATE FUNCTION gen_uuid(VARCHAR, INT) RETURNS VARCHAR AS $$/*字符串加上数字组成递增的ID*/DECLARE    str ALIAS FOR $1;			/*字符串*/    num_order ALIAS FOR $2;		/*数字*/    temp_str VARCHAR;    res VARCHAR;BEGIN    temp_str := md5(str);    res := substring(temp_str, 1, 25) || CAST(to_hex(16777216 + num_order) AS VARCHAR);    RETURN res;END;$$LANGUAGE plpgsql;/*得到身份证号码最后一位*/DROP FUNCTION IF EXISTS get_verify(VARCHAR);CREATE FUNCTION get_verify(VARCHAR) RETURNS VARCHAR AS $$/*得到身份证最后一位*/DECLARE 	id_card ALIAS FOR $1;	val_code_arr VARCHAR ARRAY := ARRAY['1','0','X','9','8','7','6','5','4','3','2'];	wi INT ARRAY := ARRAY[7,9,10,5,8,4,2,1,6,3,7,9,10,5,8,4,2];	totalNum INT := 0;	mod_value INT;BEGIN	FOR i IN 1..17 loop		totalNum := totalNum + CAST( substring(id_card, i, 1) AS INT) * wi[i];	END loop;		mod_value = mod(totalNum, 11);	RETURN val_code_arr[mod_value + 1];END;$$LANGUAGE plpgsql;/*生成身份证号*/DROP FUNCTION IF EXISTS gen_idcard(VARCHAR);CREATE FUNCTION gen_idcard(VARCHAR) RETURNS VARCHAR AS $$/*传入区县code生成身份证号*/DECLARE	id_card VARCHAR;	qx_code ALIAS FOR $1;	birthday INT;	b_year INT;	b_month INT;	b_day INT;	ranNum VARCHAR;	last_str VARCHAR;		res VARCHAR;BEGIN 	b_year := 1906 + random() * 100;	b_month := get_random_number(1, 12);	CASE b_month WHEN 1,3,5,7,8,10,12 THEN			b_day := get_random_number(1, 31);	WHEN 4,6,9,11 THEN			b_day := get_random_number(1, 30);	ELSE			IF mod(b_year, 4) &gt; 0 THEN					b_day := get_random_number(1, 29);			ELSE 				b_day :=get_random_number(1, 28);			END IF;	END CASE;	birthday = b_year * 10000 + b_month * 100 + b_day;	ranNum := substring(CAST(1000 + random() * 999 AS VARCHAR), 2, 3);	id_card := qx_code || birthday || ranNum;	last_str := get_verify(id_card);	res := id_card || last_str;	RETURN res;END;$$LANGUAGE plpgsql;/*通过身份证号得到出生年月日*/DROP FUNCTION IF EXISTS get_birth_by_idcard(VARCHAR);CREATE FUNCTION get_birth_by_idcard(VARCHAR) RETURNS DATE AS $$DECLARE	temp INT;	year_str VARCHAR DEFAULT substring($1, 7, 4);	mon_str VARCHAR DEFAULT substring($1, 11, 2);	day_str VARCHAR DEFAULT substring($1, 13, 2);	temp_str VARCHAR;BEGIN	temp_str := year_str || '-' || mon_str || '-' || day_str;	RETURN temp_str::DATE;END;$$LANGUAGE plpgsql;/*通过身份证号得到性别*/DROP FUNCTION IF EXISTS get_gender_by_idcard(VARCHAR);CREATE FUNCTION get_gender_by_idcard(VARCHAR) RETURNS VARCHAR AS $$DECLARE	temp INT;BEGIN	temp := CAST(substring($1, 17, 1) AS INTEGER);	IF mod(temp, 2) &gt; 0 THEN		/*男*/		RETURN '1';	ELSE		/*女*/		RETURN '2';	END IF;END;$$LANGUAGE plpgsql;/*得到一个随机名字*/DROP FUNCTION IF EXISTS get_random_name();CREATE FUNCTION get_random_name() RETURNS VARCHAR AS $$/*随机生成一个名字*/DECLARE    boy_str VARCHAR := '仲基,宗纬,长文,天明,志泽,明杰,弘文,烨伟,文博,天佑,文昊,修杰,苑博,鹏涛,炎彬,烨华,' || 		'煜祺,智宸,昊然,鹤轩,伟泽,哲瀚,雨泽,楷瑞,建辉,致远,俊驰,雨泽,烨磊,黎昕,青枫,旭尧,英杰,浩宇,峻熙,' || 		'嘉懿,煜城,圣杰,俊楠,鸿涛,伟祺,荣轩,君昊,熠彤,鸿煊,博涛,苑杰,黎昕,烨霖,懿轩,昊祯,龙恩,瑾瑜,伯懿,' || 		'伯毅,炫琰,金鑫,柠浩,嘉熙,贝玺,子默,思远,浩轩,语堂,昕宇,家宇,宇豪,宇鞅,宇轩,绍衡,鸿儒,鹏威,君浩,' || 		'昊东,子骞,博文,鸿飞,尚卿,尚博,峻熙,俊轩,冠佑,子丹,子文,伟霆,朝伟,富成,信哲,承哲,振东,杰伦,霸天,' || 		'天虎,宗宪,承豪,承浩,敏浩,珉浩,' ||        '明,登,维,源,升,应,廷,绍,宗,兴,世,泽,继,祖,远,昌,荣,建,国,恒,光,辉,思,孝,友,在,朝,学,贤,能,俊,杰,' ||        '挥,先,绪,英,雄,显,厚,立,敬,兴,贤,哲,诗,书,衔,吉,祥,渊,源,经,学,远,同,荣,智,永,芳,声,鸿,名,振,显,' ||        '道,达,德,宣,扬,承,序,志,培,植,怡,谟,贵,善,良,修,齐,传,泽,厚,敦,睦,裕,基,长,本,固,枝,皆,茂,家,宜,' ||        '枫,羽,聪,刚,斌,彬,彪,健,勇,鹏,强,植,睿,贝,渊,非,今,所,能,逆,料,也,子,孙,酌,而,易,之,又,吾,之,所';    girl_str VARCHAR := '梦夏,思涵,启维,思恩,诗涵,易涵,晶锦,莫愁,静琪,诗婧,诗茵,思颖,政颖,语嫣,娅维,世恩,' ||		'慧乔,紫晴,慧娴,雨晴,佳怡,心怡,静妍,梦雨,梦妍,梦冰,梦雪,淑仪,淑怡,亦菲,静姝,宝英,宝珍,' ||        '雪妍,维贞,雪莉,智英,静雅,茹芸,欣妍,雅雯,梦洁,梦瑶,碧晨,桂英,佳琳,家琳,晨曦,丞琳,雨欣,思雨,思露,凡华,' || 		'千华,秀妍,雪琴,雪芹,凡,佳,嘉,琼,勤,珍,贞,莉,桂,' ||        '娣,叶,璧,娅,琦,晶,妍,茜,秋,珊,莎,锦,黛,青,倩,婷,姣,婉,娴,瑾,颖,露,瑶,怡,婵,雁,蓓,纨,仪,荷,丹,蓉,眉,' ||        '保,东,文,辉,力,明,永,健,世,广,志,义,兴,良,海,山,仁,波,宁,贵,福,生,龙,元,全,国,胜,学,祥,才,发,武,新,利,' ||        '清,飞,彬,富,顺,信,子,杰,涛,昌,成,康,星,光,天,达,安,岩,中,茂,进,林,有,坚,和,彪,博,诚,先,敬,震,振,壮,会,' ||        '思,群,豪,心,邦,承,乐,绍,功,松,善,厚,庆,磊,民,友,裕,河,哲,江,超,浩,亮,政,谦,亨,奇,固,之,轮,翰,朗,伯,宏,' ||        '静,颖,琪,巧,燕,梅,琦,维,霞,莉,凤,姝,琳,瑶,洁,璐,涵,蓉,姬,婵,雨,鸢,冰,梦,雪,娜,时,泰,盛,雄,琛,钧,冠,策';    boy_arr VARCHAR ARRAY := regexp_split_to_array(boy_str, E',');    girl_arr VARCHAR ARRAY := regexp_split_to_array(girl_str, E',');    ran_int INT := get_random_number(1, 100);    res VARCHAR;BEGIN    IF ran_int &lt; 50 THEN        res := get_random_surname() || get_string_from_arr(girl_arr);    ELSE        res := get_random_surname() || get_string_from_arr(boy_arr);    END IF;    RETURN res;END;$$LANGUAGE plpgsql;/*得到一个随机姓氏*/DROP FUNCTION IF EXISTS get_random_surname();CREATE FUNCTION get_random_surname() RETURNS VARCHAR AS $$/*随机生成一个姓氏*/DECLARE    surname_str VARCHAR := '赵,钱,孙,李,周,吴,郑,王,冯,陈,褚,卫,蒋,沈,韩,杨,朱,秦,尤,许,何,吕,施,' || 		'张,孔,曹,严,华,金,魏,陶,姜,戚,谢,邹,喻,柏,水,窦,章,云,苏,潘,葛,奚,范,彭,郎,鲁,韦,昌,马,苗,' || 		'凤,花,方,俞,任,袁,柳,酆,鲍,史,唐,费,廉,岑,薛,雷,贺,倪,汤,滕,殷,罗,毕,郝,邬,安,常,乐,于,时,' || 		'傅,皮,卞,齐,康,伍,余,元,卜,顾,孟,平,黄,和,穆,萧,尹,姚,邵,湛,汪,祁,毛,禹,狄,米,贝,明,臧,计,' || 		'伏,成,戴,谈,宋,茅,庞,熊,纪,舒,屈,项,祝,董,梁,杜,阮,蓝,闵,席,季,麻,强,贾,路,娄,危,江,童,颜,' || 		'郭,梅,盛,林,刁,锺,徐,邱,骆,高,夏,蔡,田,樊,胡,凌,霍,虞,万,支,柯,昝,管,卢,莫,经,房,裘,缪,干,' || 		'解,应,宗,丁,宣,贲,邓,郁,单,杭,洪,包,诸,左,石,崔,吉,钮,龚,程,嵇,邢,滑,裴,陆,荣,翁,荀,羊,於,' || 		'惠,甄,麴,家,封,芮,羿,储,靳,汲,邴,糜,松,井,段,富,巫,乌,焦,巴,弓,牧,隗,山,谷,车,侯,宓,蓬,全,' || 		'郗,班,仰,秋,仲,伊,宫,宁,仇,栾,暴,甘,钭,历,戎,祖,武,符,刘,景,詹,束,龙,叶,幸,司,韶,郜,黎,蓟,' || 		'溥,印,宿,白,怀,蒲,邰,从,鄂,索,咸,籍,赖,卓,蔺,屠,蒙,池,乔,阳,郁,胥,能,苍,双,闻,莘,党,翟,谭,' || 		'贡,劳,逄,姬,申,扶,堵,冉,宰,郦,雍,却,璩,桑,桂,濮,牛,寿,通,边,扈,燕,冀,僪,浦,尚,农,温,别,庄,' || 		'晏,柴,瞿,阎,充,慕,连,茹,习,宦,艾,鱼,容,向,古,易,慎,戈,廖,庾,终,暨,居,衡,步,都,耿,满,弘,匡,' || 		'国,文,寇,广,禄,阙,东,欧,殳,沃,利,蔚,越,夔,隆,师,巩,厍,聂,晁,勾,敖,融,冷,訾,辛,阚,那,简,饶,' || 		'空,曾,毋,沙,乜,养,鞠,须,丰,巢,关,蒯,相,查,后,荆,红,游,竺,权,逮,盍,益,桓,公,万俟,司马,上官,' || 		'欧阳,夏侯,诸葛,闻人,东方,赫连,皇甫,尉迟,百里,东郭,南门,呼延,归海';    surname_arr VARCHAR ARRAY := regexp_split_to_array(surname_str, E',');    res VARCHAR;BEGIN    res := get_string_from_arr(surname_arr);    RETURN res;END;$$LANGUAGE plpgsql;/*得到随机电话号码*/DROP FUNCTION IF EXISTS get_random_lxdh();CREATE FUNCTION get_random_lxdh() RETURNS VARCHAR AS $$DECLARE	tel_str VARCHAR DEFAULT '134,135,136,137,138,139,150,151,152,157,158,159,130,131,132,155,156,133,153,180,181,182,183';	tel_arr VARCHAR ARRAY := regexp_split_to_array(tel_str, E',');	temp VARCHAR;	res VARCHAR;BEGIN	temp := get_random_num_string(8);	res := get_string_from_arr(tel_arr) || temp;	RETURN res;END;$$LANGUAGE plpgsql;/*生成随机数字*/DROP FUNCTION IF EXISTS get_random_number(INT, INT);CREATE FUNCTION get_random_number(INT, INT) RETURNS INT AS $$/*传入开始数和结束数，得到中间的一个随机数*/DECLARE    start_int ALIAS FOR $1 ; end_int ALIAS FOR $2 ;/* 第一个数表示开始数，第二个数表示结束数*/BEGIN    RETURN trunc(        random() * (end_int - start_int + 1) + start_int    ) ;END ;$$LANGUAGE plpgsql;/*从字符串数组随机获得一个字符*/DROP FUNCTION IF EXISTS get_string_from_arr(VARCHAR ARRAY);CREATE FUNCTION get_string_from_arr(VARCHAR ARRAY) RETURNS VARCHAR AS $$/*从字符串数组随机获得一个字符,传入一个字符串数组*/DECLARE    res VARCHAR;    arr ALIAS FOR $1;    len INT := array_length(arr, 1);    ran_int INT := get_random_number(1, len);BEGIN    res := arr[ran_int];    RETURN res;END;$$LANGUAGE plpgsql;/*得到一个指定长度的随机字符串*/DROP FUNCTION IF EXISTS get_random_string(INT);CREATE FUNCTION get_random_string(INT) RETURNS VARCHAR AS $$DECLARE    str VARCHAR DEFAULT 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789' ;	res VARCHAR ;/* 传入参数表示想获得多长的随机字符串 */BEGIN    res = get_random_string(str, $1);	RETURN res ;END ;$$LANGUAGE plpgsql;/*得到一个指定长度的随机纯数字字符串*/DROP FUNCTION IF EXISTS get_random_num_string(INT);CREATE FUNCTION get_random_num_string(INT) RETURNS VARCHAR AS $$DECLARE    str VARCHAR DEFAULT '0123456789' ;	res VARCHAR ;/* 传入参数表示想获得多长的随机字符串 */BEGIN    res = get_random_string(str, $1);	RETURN res ;END ;$$LANGUAGE plpgsql;/*传入一个字符串，和想要得到的字符串长度，得到一个指定长度的随机字符串*/DROP FUNCTION IF EXISTS get_random_string(VARCHAR,INT);CREATE FUNCTION get_random_string(VARCHAR,INT) RETURNS VARCHAR AS $$DECLARE    str ALIAS FOR $1;	res VARCHAR ;/* 传入参数表示想获得多长的随机字符串 */BEGIN    SELECT        array_to_string(            ARRAY (                SELECT                    SUBSTRING (                        str                        FROM                            (                                CEIL (random() * CHAR_LENGTH(str))                            ) :: INT FOR 1                    )                FROM                    generate_series (1, $2)            ),            ''        ) INTO res ;	RETURN res ;END ;$$LANGUAGE plpgsql;/*得到一个随机日期*/DROP FUNCTION IF EXISTS get_random_date(start_date date, end_date date);CREATE FUNCTION get_random_date(start_date date, end_date date) RETURNS DATE AS $$/*传入开始日期和结束日期，得到其区间内的一个随机日期*/DECLARE      interval_days integer;      random_days integer;      random_date DATE;  BEGIN      interval_days := end_date - start_date;      random_days := get_random_number(0, interval_days);     random_date := start_date + random_days;      RETURN random_date;  END;  $$LANGUAGE plpgsql;/*得到一个随机timestamp*/DROP FUNCTION IF EXISTS get_random_datetime(start_date date, end_date date);CREATE FUNCTION get_random_datetime(start_date date, end_date date) RETURNS TIMESTAMP AS $$/*传入开始日期和结束日期，得到其区间内的一个随机timestamp*/DECLARE    	interval_days integer; 	random_seconds integer;  	random_dates integer;	random_date date;  	random_time time; BEGIN	interval_days := end_date - start_date; 	random_dates:= trunc(random() * interval_days);	random_date := start_date + random_dates; 	random_seconds:= trunc(random() * 3600 * 24); 	random_time:=' 00:00:00'::time + (random_seconds || ' second')::INTERVAL; 	RETURN random_date + random_time;  END;  $$LANGUAGE plpgsql;/*得到随机是和否，传入的参数表示多少概率得到的结果为是；比如传入参数为80，则百分之80的结果为是*/DROP FUNCTION IF EXISTS get_random_sf(INT);CREATE FUNCTION get_random_sf(INT) RETURNS VARCHAR AS $$DECLARE    c_result VARCHAR(2);    n_random INT;BEGIN    n_random := trunc(random() * 100);    IF n_random &lt; $1 THEN        c_result := '1';    ELSE        c_result := '2';    END IF;    RETURN c_result;END;$$LANGUAGE plpgsql;/*得到居民家庭类型,也可用于得到随机的1,2,3,*/DROP FUNCTION IF EXISTS get_random_three();CREATE FUNCTION get_random_three() RETURNS VARCHAR AS $$DECLARE 	jtlx_arr VARCHAR ARRAY := ARRAY['1','2','3'];	ranNum INT := get_random_number(1, 3);	res VARCHAR;BEGIN	res := arr[ranNum];	RETURN res;END ; $$LANGUAGE plpgsql;/*得到随机的1,2,3,4*/DROP FUNCTION IF EXISTS get_random_four();CREATE FUNCTION get_random_four() RETURNS VARCHAR AS $$DECLARE 	arr VARCHAR ARRAY := ARRAY['1','2','3','4'];	ranNum INT := get_random_number(1, 4);	res VARCHAR;BEGIN	res := arr[ranNum];	RETURN res;END ;$$LANGUAGE plpgsql;/*得到随机的1,2,3,4,5*/DROP FUNCTION IF EXISTS get_random_five();CREATE FUNCTION get_random_five() RETURNS VARCHAR AS $$ DECLARE 	arr VARCHAR ARRAY := ARRAY['1','2','3','4','5'];	ranNum INT := get_random_number(1, 5);	res VARCHAR;BEGIN	res := arr[ranNum];	RETURN res;END ; $$LANGUAGE plpgsql;/*释放死锁*//* DROP FUNCTION IF EXISTS cancel_lock(VARCHAR);CREATE FUNCTION cancel_lock(VARCHAR) RETURNS void AS $$DECLARE 	tableName ALIAS FOR $1; 	c_ref refcursor;	res record;BEGIN	OPEN c_ref FOR SELECT aa.pid FROM pg_stat_activity aa,			(				SELECT					A .locktype,					A . DATABASE,					A .pid,					A . MODE,					A .relation,					b.relname				FROM					pg_locks A				JOIN pg_class b ON A .relation = b.oid				WHERE					UPPER (b.relname) = tableName			) bb			WHERE				aa.pid = bb.pid			AND aa.waiting = 't'	FETCH c_ref INTO res;	while FOUND LOOP		select pg_cancel_backend(res.pid);		FETCH c_ref INTO res;	END LOOP;END ; $$LANGUAGE plpgsql; *//*更新主键cbh*//* DROP FUNCTION IF EXISTS update_cbh();CREATE FUNCTION update_cbh() RETURNS INT AS $$DECLARE 	icount INT DEFAULT 0;	random_str VARCHAR DEFAULT get_random_string(32);	c_ref refcursor;	res record;BEGIN	OPEN c_ref FOR SELECT * FROM db_mozhengfly.t_user;	FETCH c_ref INTO res;	while FOUND LOOP		icount := icount + 1;		update db_mozhengfly.t_user set c_bh = gen_uuid(random_str, icount) where c_bh = res.c_bh;		FETCH c_ref INTO res;	END LOOP;	return icount;END ; $$LANGUAGE plpgsql; */

存储过程DROP FUNCTION IF EXISTS gen_user_data(INT);CREATE FUNCTION gen_user_data(INT) RETURNS INTEGER AS $$DECLARE	icount ALIAS FOR $1;	random_str VARCHAR DEFAULT get_random_string(32);	start_date DATE DEFAULT get_random_date('2017-05-01','2017-06-01');	end_date DATE DEFAULT get_random_date('2017-06-01','2017-07-01');BEGIN	FOR i IN 1..icount LOOP		INSERT INTO db_mozhengfly.t_user VALUES (gen_uuid(random_str, i), '这是第' || i || '们', get_random_number(4, 10), get_random_number(4, 10),				start_date, end_date, get_random_sf(50), get_random_string(16));	END LOOP;	RETURN icount;END;$$LANGUAGE plpgsql;

处理数据的存储过程CREATE OR REPLACE FUNCTION process_zcfz_bb_history_data () RETURNS VARCHAR AS $$ DECLARE	res VARCHAR := '';	single_res VARCHAR := '';	c_ref refcursor;	v_record record;	exp_arr VARCHAR ARRAY;	data_val NUMERIC;		v_val_record record;		var_a record;	var_b record;		executePrSql VARCHAR;		i_status INT := 0;	update_sql VARCHAR;BEGIN	OPEN c_ref FOR (select bh, data, exp from table_user);	FETCH c_ref INTO v_record;	-- 循环处理数据	WHILE FOUND LOOP		data_val := 0;				-- 解析exp		exp_arr := regexp_split_to_array(v_record.exp, '\+');		-- 数组循环		FOR var IN array_lower(exp_arr, 1)..array_upper(exp_arr, 1) LOOP-- 			RAISE NOTICE 'exp :  % [%]', v_record.c_bh, exp_arr[var];			IF position('-' in exp_arr[var]) &gt; 0 THEN				exp_arr := regexp_split_to_array(v_record.exp, '-');				executePrSql := 'select * from t_test';				EXECUTE executePrSql INTO var_a;				executePrSql := 'select * from t_test';				EXECUTE executePrSql INTO var_b;								data_val := var_a.data_val - var_b.data_val;			ELSE				executePrSql := 'select * from test';-- 			RAISE NOTICE 'SQL : %', executePrSql;							EXECUTE executePrSql INTO v_val_record;								data_val := data_val + v_val_record.data_val;			END IF;		END LOOP;				i_status := 0;		IF data_val != v_record.data_val THEN				RAISE NOTICE '提示 [data_val][%] 结果不等:  计算结果 [%] 数据库值 [%]', v_record.c_bbzd, qc_val, v_record.n_qcye;				i_status := 1;		END IF;		IF i_status &gt; 0 THEN				update_sql := 'update test set data_val = ' || data_val || ' where c_bh = ''' || v_record.c_bh || '''';				RAISE NOTICE '执行更新: [%]', update_sql;				EXECUTE update_sql;		END IF;				FETCH c_ref INTO v_record;	END LOOP;		RETURN res;END;$$ LANGUAGE plpgsql;

多个服务中只调用指定一个服务
需求描述：在一个注册中心里面有多个名为user-service的服务，使用Feign 进行服务调用的时候期望永远只调用指定的那一个服务。

// 调用方代码@FeignClient(value = "user-service", path = "/api/v1/user")public interface IUserService &#123;    @GetMapping("&#123;id&#125;")    User getUserById(@PathVariable String id);&#125;
解决思路查看了相关文档，发现ribbon会维护eureka的服务实例，默认有过滤服务实例的策略，默认实现类为ZonePreferenceServerListFilter。

ZonePreferenceServerListFilter：使用Spring Cloud 整合Ribbon默认会使用该过滤器，他实现了通过配置或者Eureka实例元数据的所属区域（Zone）来过滤出同区域的服务实例，首先通过父类ZoneAffinityServerListFilter获取“区域感知”的服务实例列表，然后遍历取出根据消费者配置预设的区域Zone来进行过滤，如果结果为空则直接返回父类获取的结果，不为空返回通过消费者配置的Zone过滤后的结果。

// 关键源码@Overridepublic List&lt;Server&gt; getFilteredListOfServers(List&lt;Server&gt; servers) &#123;	List&lt;Server&gt; output = super.getFilteredListOfServers(servers);	if (this.zone != null &amp;&amp; output.size() == servers.size()) &#123;		List&lt;Server&gt; local = new ArrayList&lt;&gt;();		for (Server server : output) &#123;			if (this.zone.equalsIgnoreCase(server.getZone())) &#123;				local.add(server);			&#125;		&#125;		if (!local.isEmpty()) &#123;			return local;		&#125;	&#125;	return output;&#125;
源码分析发现，使用策略是eureka实例的元数据进行比较过滤的，配置key为eureka.instance.metadata-map.zone
解决办法在调用方和被调用方（只配置一个）均配置eureka.instance.metadata-map.zone为同一个值，这样就会过滤掉元数据zone不一致的服务，从而达到在众多服务中，每次调用服务的时候都只调用一个指定的服务实例的效果。注意的是：只能在想调用的指定服务中配置，不然配置多了就会维护多个服务示例，到时候还是默认轮询调用。
例如：
&#x2F;&#x2F; 调用方配置eureka.instance.metadata-map.zone&#x3D;wangchonglin&#x2F;&#x2F; 被调用方配置eureka.instance.metadata-map.zone&#x3D;wangchonglin
